package ingest

import (
	"regexp"
	"strings"
)

// 4-level priority for section ID extraction from ## headings:
// 1. Lettered: "A.1", "B.2.3" — pattern like A.1 - Title
// 2. Numbered prefix with dot: "3." — pattern like 3. Title
// 3. Simple number: "3" — pattern like 3 Title
// 4. Slug fallback: "my-custom-section"

var (
	// Lettered: matches "A.1", "A.1.2", "B.3" etc. at the start
	letteredRe = regexp.MustCompile(`^([A-Z]\.\d+(?:\.\d+)*)`)
	// Numbered with dot: matches "3." at the start
	numberedDotRe = regexp.MustCompile(`^(\d+)\.`)
	// Simple number: matches a standalone number at the start
	simpleNumberRe = regexp.MustCompile(`^(\d+)\s`)
	// Slug cleanup
	slugCleanRe    = regexp.MustCompile(`[^a-z0-9-]+`)
	slugCollapseRe = regexp.MustCompile(`-{2,}`)
)

// ExtractSectionID extracts a section identifier from a heading line.
// The heading text should NOT include the ## prefix.
func ExtractSectionID(heading string) (id string, title string) {
	heading = strings.TrimSpace(heading)
	if heading == "" {
		return "untitled", ""
	}

	// Try lettered (A.1 - Title or A.1 Title)
	if m := letteredRe.FindStringSubmatch(heading); m != nil {
		id = m[1]
		rest := strings.TrimPrefix(heading, id)
		rest = strings.TrimLeft(rest, " -")
		return id, strings.TrimSpace(rest)
	}

	// Try numbered with dot (3. Title)
	if m := numberedDotRe.FindStringSubmatch(heading); m != nil {
		id = m[1]
		rest := strings.TrimPrefix(heading, m[0])
		return id, strings.TrimSpace(rest)
	}

	// Try simple number (3 Title) — number must be followed by space
	if m := simpleNumberRe.FindStringSubmatch(heading); m != nil {
		id = m[1]
		rest := strings.TrimPrefix(heading, m[1])
		return id, strings.TrimSpace(rest)
	}

	// Slug fallback
	slug := strings.ToLower(heading)
	slug = slugCleanRe.ReplaceAllString(slug, "-")
	slug = slugCollapseRe.ReplaceAllString(slug, "-")
	slug = strings.Trim(slug, "-")
	if slug == "" {
		return "untitled", heading
	}
	return slug, heading
}
